					EventID:   "evt-" + randomProgressID(),
					WorkerID:  runtime.WorkerID,
					ProjectID: runtime.ProjectRoot,
					Phase:     "loop.paused-infra",
					Heartbeat: true,
					TS:        now().UTC(),
					Message:   "all_infra_cooldowns",
				})
				sleepDur := time.Until(resumeAt)
				if sleepDur <= 0 {
					sleepDur = PausedInfraInterval
