func requireConcurrentScriptHarnessLandingInvariant(
	t *testing.T,
	projectRoot, ddxDir, initialSHA string,
	results []*ExecuteBeadLoopResult,
	errs []error,
	beadCount int,
) {
	t.Helper()

	failures := make([]string, 0)
	totalAttempts := 0
	totalSuccesses := 0
	executedByBead := make(map[string]int, beadCount)

	if len(results) != beadCount {
		failures = append(failures, fmt.Sprintf("worker result count=%d, want %d", len(results), beadCount))
	}
	if len(errs) != beadCount {
		failures = append(failures, fmt.Sprintf("worker error count=%d, want %d", len(errs), beadCount))
	}

	for i, err := range errs {
		if err != nil {
			failures = append(failures, fmt.Sprintf("worker %d returned error: %v", i, err))
		}
	}

	for i, result := range results {
		if result == nil {
			failures = append(failures, fmt.Sprintf("worker %d returned nil loop result", i))
			continue
		}
		totalAttempts += result.Attempts
		totalSuccesses += result.Successes
		for _, report := range result.Results {
			executedByBead[report.BeadID]++
			if report.Status != ExecuteBeadStatusSuccess {
				failures = append(failures,
					fmt.Sprintf("worker %d reported bead %s status=%s detail=%q", i, report.BeadID, report.Status, report.Detail))
			}
		}
	}

	if totalAttempts != beadCount {
		failures = append(failures, fmt.Sprintf("total attempts=%d, want %d", totalAttempts, beadCount))
	}
	if totalSuccesses != beadCount {
		failures = append(failures, fmt.Sprintf("total successes=%d, want %d", totalSuccesses, beadCount))
	}

	for i := 1; i <= beadCount; i++ {
		beadID := fmt.Sprintf("ddx-int-%04d", i)
		if got := executedByBead[beadID]; got != 1 {
			failures = append(failures, fmt.Sprintf("bead %s executed %d times, want exactly once", beadID, got))
		}
	}

	store := bead.NewStore(ddxDir)
	all, err := store.List("", "", nil)
	if err != nil {
		failures = append(failures, fmt.Sprintf("list beads: %v", err))
	} else {
		byID := make(map[string]bead.Bead, len(all))
		closedCount := 0
		for _, item := range all {
			byID[item.ID] = item
			if item.Status == bead.StatusClosed {
				closedCount++
			}
		}
		if len(all) != beadCount {
			failures = append(failures, fmt.Sprintf("bead count=%d, want %d", len(all), beadCount))
		}
		if closedCount != beadCount {
			failures = append(failures, fmt.Sprintf("closed bead count=%d, want %d", closedCount, beadCount))
		}
		for i := 1; i <= beadCount; i++ {
			beadID := fmt.Sprintf("ddx-int-%04d", i)
			item, ok := byID[beadID]
			if !ok {
				failures = append(failures, fmt.Sprintf("missing bead row for %s", beadID))
				continue
			}
			if item.Status != bead.StatusClosed {
				failures = append(failures, fmt.Sprintf("bead %s status=%s, want closed", beadID, item.Status))
			}
			if closingSHA := extraString(item.Extra, "closing_commit_sha"); closingSHA == "" {
				failures = append(failures, fmt.Sprintf("bead %s missing closing_commit_sha", beadID))
			}
		}
	}

	commitsOnMain, err := gitCommitCountOutput(projectRoot, "HEAD", "--not", initialSHA)
	if err != nil {
		failures = append(failures, fmt.Sprintf("count commits on main: %v", err))
	} else if commitsOnMain < beadCount {
		failures = append(failures,
			fmt.Sprintf("commits on main since seed=%d, want at least %d", commitsOnMain, beadCount))
	}

		writeQueueSnapshotTerminalSummary(w, result.QueueSnapshot)
		return nil
	}

	fmt.Fprintf(w, "\nproject: %s\n", projectRoot)
	writeWorkTerminalSummary(w, result)
	writeOperatorAttentionSummary(w, result.OperatorAttention)
	preserved := preservedWorkAttempts(result)
	if len(preserved) > 0 {
		fmt.Fprintf(w, "\npreserved:\n")
		for _, attempt := range preserved {
			fmt.Fprintf(w, "  - %s: %s", attempt.BeadID, attempt.Detail)
			if attempt.PreserveRef != "" {
				fmt.Fprintf(w, " (%s)", attempt.PreserveRef)
			}
			fmt.Fprintln(w)
		}
	}
	failed := failedWorkAttempts(result)
	if len(failed) > 0 {
		fmt.Fprintf(w, "\nfailed:\n")
		for _, attempt := range failed {
			fmt.Fprintf(w, "  - %s: %s", attempt.BeadID, attempt.Detail)
			if attempt.PreserveRef != "" {
				fmt.Fprintf(w, " (preserved)")
			}
			fmt.Fprintln(w)
		}
	}
	if result.NoReadyWork {
		fmt.Fprintln(w)
		writeNoReadyWorkSummary(w, "", result.NoReadyWorkDetail)
		writeQueueSnapshotTerminalSummary(w, result.QueueSnapshot)
	}
	return nil
}

func writeWorkTerminalSummary(w io.Writer, result *agent.ExecuteBeadLoopResult) {
	closed, changed, alreadySatisfied, preserved := countWorkTerminalOutcomes(result)
	fmt.Fprintf(w, "worker exited: %s\n", workExitSummary(result))
	fmt.Fprintf(w, "attempts: %d  |  closed: %d  |  changed: %d  |  already-satisfied: %d  |  preserved: %d  |  failures: %d\n",
		result.Attempts, closed, changed, alreadySatisfied, preserved, result.Failures)
}

func writeOperatorAttentionSummary(w io.Writer, stop *agent.OperatorAttentionStop) {
	if stop == nil {
		return
	}
	fmt.Fprintln(w)
	fmt.Fprintln(w, "operator attention:")
	if stop.BeadID != "" {
		fmt.Fprintf(w, "  released bead: %s\n", stop.BeadID)
	}
	if stop.Message != "" {
		fmt.Fprintf(w, "  %s\n", stop.Message)
	}
	if stop.ProjectRoot != "" {
		fmt.Fprintf(w, "  project root: %s\n", stop.ProjectRoot)
	}
	if len(stop.DirtyPaths) > 0 {
		fmt.Fprintf(w, "  dirty paths: %s\n", strings.Join(stop.DirtyPaths, ", "))
	}
}

func countWorkTerminalOutcomes(result *agent.ExecuteBeadLoopResult) (closed, changed, alreadySatisfied, preserved int) {
	for _, attempt := range result.Results {
		switch attempt.Status {
		case agent.ExecuteBeadStatusSuccess:
			closed++
			changed++
		case agent.ExecuteBeadStatusAlreadySatisfied:
			closed++
			alreadySatisfied++
		case agent.ExecuteBeadStatusPreservedNeedsReview:
			preserved++
		}
	}
	if closed == 0 && result.Successes > 0 {
		closed = result.Successes
	}
	return closed, changed, alreadySatisfied, preserved
}

func preservedWorkAttempts(result *agent.ExecuteBeadLoopResult) []agent.ExecuteBeadReport {
	if result == nil {
		return nil
	}
	var out []agent.ExecuteBeadReport
	for _, attempt := range result.Results {
		if attempt.Status == agent.ExecuteBeadStatusPreservedNeedsReview {
			out = append(out, attempt)
		}
	}
	return out
}

func failedWorkAttempts(result *agent.ExecuteBeadLoopResult) []agent.ExecuteBeadReport {
	if result == nil {
		return nil
	}
	var out []agent.ExecuteBeadReport
	for _, attempt := range result.Results {
		switch attempt.Status {
		case agent.ExecuteBeadStatusSuccess,
			agent.ExecuteBeadStatusAlreadySatisfied,
			agent.ExecuteBeadStatusPreservedNeedsReview:
			continue
		default:
			out = append(out, attempt)
		}
	}
	return out
}

func workExitSummary(result *agent.ExecuteBeadLoopResult) string {
	switch result.ExitReason {
	case "drained":
		return "drained current execution-ready queue"
	case "once_complete":
		return "once complete"
	case "budget":
		return "budget reached"
	case "no_progress":
		return "no-progress policy stopped work"
	case "blocked":
		return "blocked waiting for external action"
	case "operator_attention":
		return "operator attention required"
	case "sigint", "sigterm", "context_cancelled":
		return "stopped by signal"
	case "fatal_config":
		return "fatal configuration error"
	case "preflight_failed":
		return "preflight failed"
	case "resource_exhausted":
		return "resource exhausted"
	case "routing_unavailable":
		return "routing unavailable"
	}
	if result.StopCondition != "" {
		return strings.ToLower(strings.ReplaceAll(result.StopCondition, "_", " "))
	}
	return "completed"
}

func writeQueueSnapshotTerminalSummary(w io.Writer, snapshot *agent.QueueSnapshot) {
	if snapshot == nil {
		return
	}
	retry := ""
	if snapshot.NextRetryAfter != "" {
		retry = " next-retry=" + snapshot.NextRetryAfter
	}
	fmt.Fprintf(w, "remaining queue: execution-ready=%d blocked=%d operator-attention=%d needs-human/investigation=%d cooldown/deferred=%d%s execution-ineligible=%d superseded=%d epics=%d epic-closure-candidates=%d\n",
		snapshot.ExecutionReadyCount,
		snapshot.BlockedCount,
		snapshot.ProposedOperatorAttentionCount,
		snapshot.HumanReviewBlockerCount,
		snapshot.RetryCooldownCount,
		retry,
		snapshot.ExecutionIneligibleCount,
		snapshot.SupersededCount,
		snapshot.SkippedEpicsCount,
		snapshot.EpicClosureCandidatesCount,
