package agent

import (
	"bytes"
	"context"
	"io"
	"os"
	"path/filepath"
	"testing"

	"github.com/DocumentDrivenDX/ddx/internal/bead"
	"github.com/DocumentDrivenDX/ddx/internal/config"
	"github.com/DocumentDrivenDX/ddx/internal/ddxroot"
	"github.com/DocumentDrivenDX/ddx/internal/testutils"
	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
)

func setupTrackerSyncProject(t *testing.T, beads ...*bead.Bead) (projectRoot, originDir, ddxDir string) {
	t.Helper()

	projectRoot, originDir, _ = setupBareOrigin(t)
	ddxDir = testutils.MakeInitializedDDxRoot(t, projectRoot)
	store := bead.NewStore(ddxDir)
	require.NoError(t, store.Init(context.Background()))
	for _, b := range beads {
		require.NoError(t, store.Create(context.Background(), b))
	}
	runGitInteg(t, projectRoot, "add", filepath.Join(ddxroot.DirName, "beads.jsonl"), filepath.Join(ddxroot.DirName, "config.yaml"))
	runGitInteg(t, projectRoot, "commit", "-m", "chore: seed tracker state")
	runGitInteg(t, projectRoot, "push", "origin", "main")
	return projectRoot, originDir, ddxDir
}

func updateOriginTracker(t *testing.T, originDir string, mutate func(*bead.Store)) {
	t.Helper()

	cloneDir := t.TempDir()
	runGitInteg(t, cloneDir, "clone", originDir, ".")
	runGitInteg(t, cloneDir, "config", "user.email", "test@ddx.test")
	runGitInteg(t, cloneDir, "config", "user.name", "DDx Test")

	store := bead.NewStore(filepath.Join(cloneDir, ddxroot.DirName))
	require.NoError(t, store.Init(context.Background()))
	mutate(store)

	runGitInteg(t, cloneDir, "add", filepath.Join(ddxroot.DirName, "beads.jsonl"), filepath.Join(ddxroot.DirName, "config.yaml"))
	runGitInteg(t, cloneDir, "commit", "-m", "chore: sync tracker from origin clone")
	runGitInteg(t, cloneDir, "push", "origin", "main")
}

func newTrackerSyncWorker(store *claimCountingStore, execFn ExecuteBeadExecutorFunc) *ExecuteBeadWorker {
	return &ExecuteBeadWorker{
		Store:    store,
		Executor: execFn,
	}
}

func runTrackerSyncWorker(t *testing.T, worker *ExecuteBeadWorker, projectRoot string, logWriter, eventSink io.Writer) *ExecuteBeadLoopResult {
	t.Helper()

	cfgOpts := config.TestLoopConfigOpts{Assignee: "worker"}
	rcfg := config.NewTestConfigForLoop(cfgOpts).Resolve(config.TestLoopOverrides(cfgOpts))
	result, err := worker.Run(context.Background(), rcfg, ExecuteBeadLoopRuntime{
		Once:         true,
		TrackerSync:  true,
		ProjectRoot:  projectRoot,
		SessionID:    "sess-tracker-sync",
		WorkerID:     "worker-tracker-sync",
		EventSink:    eventSink,
		Log:          logWriter,
		CleanupLog:   logWriter,
	})
	require.NoError(t, err)
	require.NotNil(t, result)
	return result
}

func TestExecuteLoop_PreClaimSyncFetchesBeforeCandidateSelection(t *testing.T) {
	projectRoot, originDir, _ := setupTrackerSyncProject(t,
		&bead.Bead{ID: "ddx-sync-a", Title: "closed on origin", Priority: 0},
		&bead.Bead{ID: "ddx-sync-b", Title: "next ready bead", Priority: 1},
	)

	updateOriginTracker(t, originDir, func(store *bead.Store) {
		require.NoError(t, store.Close(context.Background(), "ddx-sync-a"))
	})

	claimed := []string{}
	worker := newTrackerSyncWorker(&claimCountingStore{
		Store: bead.NewStore(filepath.Join(projectRoot, ddxroot.DirName)),
	}, ExecuteBeadExecutorFunc(func(ctx context.Context, beadID string) (ExecuteBeadReport, error) {
		claimed = append(claimed, beadID)
		return ExecuteBeadReport{
			BeadID:    beadID,
			Status:    ExecuteBeadStatusSuccess,
			SessionID: "sess-pre-claim",
			ResultRev: "result-pre-claim",
		}, nil
	}))

	result := runTrackerSyncWorker(t, worker, projectRoot, &bytes.Buffer{}, &bytes.Buffer{})
	require.Len(t, claimed, 1)
	assert.Equal(t, "ddx-sync-b", claimed[0], "pre-claim sync must skip beads closed on origin")
	assert.Equal(t, 1, result.Successes)
}

func TestExecuteLoop_PostClaimPushPublishesClaim(t *testing.T) {
	projectRoot, originDir, _ := setupTrackerSyncProject(t,
		&bead.Bead{ID: "ddx-sync-claim", Title: "claim publish", Priority: 0},
	)

	worker := newTrackerSyncWorker(&claimCountingStore{
		Store: bead.NewStore(filepath.Join(projectRoot, ddxroot.DirName)),
	}, ExecuteBeadExecutorFunc(func(ctx context.Context, beadID string) (ExecuteBeadReport, error) {
		freshDir := t.TempDir()
		runGitInteg(t, freshDir, "clone", originDir, ".")
		freshStore := bead.NewStore(filepath.Join(freshDir, ddxroot.DirName))
		got, err := freshStore.Get(context.Background(), beadID)
		require.NoError(t, err)
		require.Equal(t, bead.StatusInProgress, got.Status, "claim must be visible on origin before execution begins")
		require.NotEmpty(t, got.Owner, "origin clone must see an owner on the claimed bead")
		return ExecuteBeadReport{
			BeadID:    beadID,
			Status:    ExecuteBeadStatusSuccess,
			SessionID: "sess-post-claim",
			ResultRev: "result-post-claim",
		}, nil
	}))

	result := runTrackerSyncWorker(t, worker, projectRoot, &bytes.Buffer{}, &bytes.Buffer{})
	assert.Equal(t, 1, result.Successes)
}

func TestExecuteLoop_PostCloseSyncPushesClose(t *testing.T) {
	projectRoot, originDir, _ := setupTrackerSyncProject(t,
		&bead.Bead{ID: "ddx-sync-close", Title: "close publish", Priority: 0},
	)

	worker := newTrackerSyncWorker(&claimCountingStore{
		Store: bead.NewStore(filepath.Join(projectRoot, ddxroot.DirName)),
	}, ExecuteBeadExecutorFunc(func(ctx context.Context, beadID string) (ExecuteBeadReport, error) {
		return ExecuteBeadReport{
			BeadID:    beadID,
			Status:    ExecuteBeadStatusSuccess,
			SessionID: "sess-post-close",
			ResultRev: "result-post-close",
		}, nil
	}))

	runTrackerSyncWorker(t, worker, projectRoot, &bytes.Buffer{}, &bytes.Buffer{})

	freshDir := t.TempDir()
	runGitInteg(t, freshDir, "clone", originDir, ".")
	freshStore := bead.NewStore(filepath.Join(freshDir, ddxroot.DirName))
	got, err := freshStore.Get(context.Background(), "ddx-sync-close")
	require.NoError(t, err)
	assert.Equal(t, bead.StatusClosed, got.Status, "post-close sync must publish the close to origin")
}

func TestExecuteLoop_PreClaimSyncDegradesWhenOriginUnreachable(t *testing.T) {
	projectRoot, originDir, _ := setupTrackerSyncProject(t,
		&bead.Bead{ID: "ddx-sync-local", Title: "local fallback", Priority: 0},
	)

	fallbackURL := filepath.Join(t.TempDir(), "gone")
	runGitInteg(t, projectRoot, "remote", "set-url", "origin", "file://"+fallbackURL)
	require.NoError(t, os.RemoveAll(originDir))

	var logBuf bytes.Buffer
	claimed := []string{}
	worker := newTrackerSyncWorker(&claimCountingStore{
		Store: bead.NewStore(filepath.Join(projectRoot, ddxroot.DirName)),
	}, ExecuteBeadExecutorFunc(func(ctx context.Context, beadID string) (ExecuteBeadReport, error) {
		claimed = append(claimed, beadID)
		return ExecuteBeadReport{
			BeadID:    beadID,
			Status:    ExecuteBeadStatusSuccess,
			SessionID: "sess-preclaim-unreachable",
			ResultRev: "result-preclaim-unreachable",
		}, nil
	}))

	result := runTrackerSyncWorker(t, worker, projectRoot, &logBuf, &bytes.Buffer{})
	require.Len(t, claimed, 1)
	assert.Equal(t, "ddx-sync-local", claimed[0], "local fallback should still claim from the stale local queue")
	assert.Equal(t, 1, result.Successes)
	assert.Contains(t, logBuf.String(), "tracker sync (pre_claim)", "pre-claim sync failure should be warned, not block the drain")
}

func TestExecuteLoop_TrackerSyncFailureEmitsOperatorAttention(t *testing.T) {
	projectRoot, originDir, _ := setupTrackerSyncProject(t,
		&bead.Bead{ID: "ddx-sync-fail", Title: "push failure", Priority: 0},
	)

	require.NoError(t, os.MkdirAll(filepath.Join(originDir, "hooks"), 0o755))
	hookPath := filepath.Join(originDir, "hooks", "pre-receive")
	require.NoError(t, os.WriteFile(hookPath, []byte("#!/bin/sh\nexit 1\n"), 0o755))

	var logBuf bytes.Buffer
	var events bytes.Buffer
	worker := newTrackerSyncWorker(&claimCountingStore{
		Store: bead.NewStore(filepath.Join(projectRoot, ddxroot.DirName)),
	}, ExecuteBeadExecutorFunc(func(ctx context.Context, beadID string) (ExecuteBeadReport, error) {
		return ExecuteBeadReport{
			BeadID:    beadID,
			Status:    ExecuteBeadStatusSuccess,
			SessionID: "sess-push-fail",
			ResultRev: "result-push-fail",
		}, nil
	}))

	result := runTrackerSyncWorker(t, worker, projectRoot, &logBuf, &events)
	assert.Equal(t, 1, result.Successes)
	assert.Contains(t, events.String(), "loop.operator_attention", "persistent push failure must surface operator attention")
	assert.Contains(t, events.String(), "tracker_sync_post_claim_failed", "post-claim push failure must be labeled in the event payload")
}

