func setupTrackerSyncProject(t *testing.T, beads ...*bead.Bead) (projectRoot, originDir, ddxDir string) {
	t.Helper()

	projectRoot, originDir, _ = setupBareOrigin(t)
	ddxDir = testutils.MakeInitializedDDxRoot(t, projectRoot)
	store := bead.NewStore(ddxDir)
	require.NoError(t, store.Init(context.Background()))
	for _, b := range beads {
		require.NoError(t, store.Create(context.Background(), b))
	}
	runGitInteg(t, projectRoot, "add", filepath.Join(ddxroot.DirName, "beads.jsonl"), filepath.Join(ddxroot.DirName, "config.yaml"))
	runGitInteg(t, projectRoot, "commit", "-m", "chore: seed tracker state")
	runGitInteg(t, projectRoot, "push", "origin", "main")
	return projectRoot, originDir, ddxDir
}

func updateOriginTracker(t *testing.T, originDir string, mutate func(*bead.Store)) {
	t.Helper()

	cloneDir := t.TempDir()
	runGitInteg(t, cloneDir, "clone", originDir, ".")
	runGitInteg(t, cloneDir, "config", "user.email", "test@ddx.test")
	runGitInteg(t, cloneDir, "config", "user.name", "DDx Test")

	store := bead.NewStore(filepath.Join(cloneDir, ddxroot.DirName))
	require.NoError(t, store.Init(context.Background()))
	mutate(store)

	runGitInteg(t, cloneDir, "add", filepath.Join(ddxroot.DirName, "beads.jsonl"), filepath.Join(ddxroot.DirName, "config.yaml"))
	runGitInteg(t, cloneDir, "commit", "-m", "chore: sync tracker from origin clone")
	runGitInteg(t, cloneDir, "push", "origin", "main")
}

func newTrackerSyncWorker(store *claimCountingStore, execFn ExecuteBeadExecutorFunc) *ExecuteBeadWorker {
	return &ExecuteBeadWorker{
		Store:    store,
		Executor: execFn,
	}
}

func runTrackerSyncWorker(t *testing.T, worker *ExecuteBeadWorker, projectRoot string, logWriter, eventSink io.Writer) *ExecuteBeadLoopResult {
	t.Helper()

	cfgOpts := config.TestLoopConfigOpts{Assignee: "worker"}
	rcfg := config.NewTestConfigForLoop(cfgOpts).Resolve(config.TestLoopOverrides(cfgOpts))
	result, err := worker.Run(context.Background(), rcfg, ExecuteBeadLoopRuntime{
		Once:         true,
		TrackerSync:  true,
		ProjectRoot:  projectRoot,
		SessionID:    "sess-tracker-sync",
		WorkerID:     "worker-tracker-sync",
		EventSink:    eventSink,
		Log:          logWriter,
		CleanupLog:   logWriter,
	})
	require.NoError(t, err)
	require.NotNil(t, result)
	return result
}

